  3→/// <summary>
  4→/// Parses JSON configuration input into a MatrixConfig object.
  5→/// Handles the GitHub Actions strategy format with kebab-case property names
  6→/// and mixed value types (strings, numbers, booleans in matrix arrays).
  7→/// </summary>
  8→public static class MatrixConfigParser
  9→{
 10→    /// <summary>
 11→    /// Parse a JSON string into a MatrixConfig.
 12→    /// Supports kebab-case property names and mixed value types in arrays.
 13→    /// </summary>
 14→    public static MatrixConfig Parse(string json)
 15→    {
 16→        if (string.IsNullOrWhiteSpace(json))
 17→            throw new ArgumentException("Configuration JSON cannot be empty.");
 18→
 19→        JsonDocument doc;
 20→        try
 21→        {
 22→            doc = JsonDocument.Parse(json);
 23→        }
 24→        catch (JsonException ex)
 25→        {
 26→            throw new ArgumentException($"Invalid JSON configuration: {ex.Message}", ex);
 27→        }
 28→
 29→        var root = doc.RootElement;
 30→
 31→        // Parse the matrix dimensions (required)
 32→        if (!root.TryGetProperty("matrix", out var matrixElement))
 33→            throw new ArgumentException("Configuration must contain a 'matrix' property with dimension definitions.");
 34→
 35→        var config = new MatrixConfig
 36→        {
 37→            Matrix = ParseMatrixDimensions(matrixElement),
 38→            Include = ParseRuleList(root, "include"),
 39→            Exclude = ParseRuleList(root, "exclude"),
 40→            FailFast = GetBoolProperty(root, "fail-fast", true),
 41→            MaxParallel = GetNullableIntProperty(root, "max-parallel"),
 42→            MaxMatrixSize = GetIntProperty(root, "max-matrix-size", 256)
 43→        };
 44→
 45→        return config;
 46→    }
 47→
 48→    /// <summary>
 49→    /// Parse matrix dimensions: { "os": ["ubuntu", "windows"], "node": [18, 20] }
 50→    /// Values can be strings, numbers, or booleans — all converted to strings.
 51→    /// </summary>
 52→    private static Dictionary<string, List<string>> ParseMatrixDimensions(JsonElement matrixElement)
 53→    {
 54→        var dimensions = new Dictionary<string, List<string>>();
 55→
 56→        foreach (var prop in matrixElement.EnumerateObject())
 57→        {
 58→            if (prop.Value.ValueKind != JsonValueKind.Array)
 59→                continue; // Skip non-array properties (like nested include/exclude)
 60→
 61→            var values = new List<string>();
 62→            foreach (var item in prop.Value.EnumerateArray())
 63→            {
 64→                values.Add(JsonValueToString(item));
 65→            }
 66→            dimensions[prop.Name] = values;
 67→        }
 68→
 69→        return dimensions;
 70→    }
 71→
 72→    /// <summary>
 73→    /// Parse include or exclude rule lists from the config.
 74→    /// </summary>
 75→    private static List<Dictionary<string, string>> ParseRuleList(JsonElement root, string propertyName)
 76→    {
 77→        var rules = new List<Dictionary<string, string>>();
 78→
 79→        if (!root.TryGetProperty(propertyName, out var arrayElement))
 80→            return rules;
 81→
 82→        if (arrayElement.ValueKind != JsonValueKind.Array)
 83→            return rules;
 84→
 85→        foreach (var item in arrayElement.EnumerateArray())
 86→        {
 87→            var rule = new Dictionary<string, string>();
 88→            foreach (var prop in item.EnumerateObject())
 89→            {
 90→                rule[prop.Name] = JsonValueToString(prop.Value);
 91→            }
 92→            rules.Add(rule);
 93→        }
 94→
 95→        return rules;
 96→    }
 97→
 98→    /// <summary>
 99→    /// Convert any JSON value to its string representation.
100→    /// Numbers, booleans, and strings are all converted to lowercase strings.
101→    /// </summary>
102→    private static string JsonValueToString(JsonElement element)
103→    {
104→        return element.ValueKind switch
105→        {
106→            JsonValueKind.String => element.GetString() ?? "",
107→            JsonValueKind.Number => element.GetRawText(),
108→            JsonValueKind.True => "true",
109→            JsonValueKind.False => "false",
110→            _ => element.GetRawText()
111→        };
112→    }
113→
