  1→// Environment Matrix Generator for GitHub Actions
  2→// .NET 10 file-based app — run with: dotnet run MatrixGenerator.cs [config.json]
  3→//
  4→// Generates a build matrix (as JSON) suitable for GitHub Actions strategy.matrix.
  5→// Supports:
  6→//   - Cartesian product of OS options, language versions, and feature flags
  7→//   - Include rules (add specific combinations)
  8→//   - Exclude rules (remove specific combinations)
  9→//   - Max-parallel limits
 10→//   - Fail-fast configuration
 11→//   - Matrix size validation (default max: 256, matching GitHub Actions limit)
 12→//
 13→// Usage:
 14→//   dotnet run MatrixGenerator.cs config.json         # Read config from file
 15→//   echo '{"matrix":...}' | dotnet run MatrixGenerator.cs  # Read from stdin
 16→//   dotnet run MatrixGenerator.cs --help              # Show usage
 17→
 18→#nullable enable
 19→
 20→using System.Text.Json;
 21→using System.Text.Json.Serialization;
 22→
 23→// --- Entry Point ---
 24→
 25→if (args.Length > 0 && args[0] is "--help" or "-h")
 26→{
 27→    PrintUsage();
 28→    return;
 29→}
 30→
 31→try
 32→{
 33→    string json = ReadInput(args);
 34→    var config = ParseConfig(json);
 35→    var result = GenerateMatrix(config);
 36→    var output = ToOutputJson(result);
 37→    Console.WriteLine(output);
 38→}
 39→catch (ArgumentException ex)
 40→{
 41→    Console.Error.WriteLine($"Configuration error: {ex.Message}");
 42→    Environment.Exit(1);
 43→}
 44→catch (InvalidOperationException ex)
 45→{
 46→    Console.Error.WriteLine($"Matrix generation error: {ex.Message}");
 47→    Environment.Exit(1);
 48→}
 49→catch (Exception ex)
 50→{
 51→    Console.Error.WriteLine($"Unexpected error: {ex.Message}");
 52→    Environment.Exit(2);
 53→}
 54→
 55→// --- Input Handling ---
 56→
 57→static string ReadInput(string[] args)
 58→{
 59→    if (args.Length > 0 && args[0] is not "--help" and not "-h")
 60→    {
 61→        var filePath = args[0];
 62→        if (!File.Exists(filePath))
 63→            throw new ArgumentException($"Configuration file not found: {filePath}");
 64→        return File.ReadAllText(filePath);
 65→    }
 66→
 67→    // Read from stdin if no file argument
 68→    if (Console.IsInputRedirected)
 69→    {
 70→        return Console.In.ReadToEnd();
 71→    }
 72→
 73→    throw new ArgumentException(
 74→        "No input provided. Pass a config file path as argument or pipe JSON to stdin. Use --help for usage.");
 75→}
 76→
 77→static void PrintUsage()
 78→{
 79→    Console.WriteLine("""
 80→    Environment Matrix Generator for GitHub Actions
 81→
 82→    Generates a build matrix (JSON) suitable for GitHub Actions strategy.matrix.
 83→
 84→    Usage:
 85→      dotnet run MatrixGenerator.cs <config.json>
 86→      cat config.json | dotnet run MatrixGenerator.cs
 87→
 88→    Config format (JSON):
 89→    {
 90→      "matrix": {
 91→        "os": ["ubuntu-latest", "windows-latest"],
 92→        "node": ["18", "20"]
 93→      },
 94→      "include": [
 95→        { "os": "ubuntu-latest", "node": "21", "experimental": "true" }
 96→      ],
 97→      "exclude": [
 98→        { "os": "windows-latest", "node": "18" }
 99→      ],
100→      "fail-fast": false,
101→      "max-parallel": 4,
102→      "max-matrix-size": 256
103→    }
104→
105→    Output: Complete strategy.matrix JSON to stdout.
106→    Errors are written to stderr with non-zero exit code.
107→    """);
108→}
109→
110→// --- Config Parsing ---
111→
112→static MatrixConfig ParseConfig(string json)
113→{
114→    if (string.IsNullOrWhiteSpace(json))
115→        throw new ArgumentException("Configuration JSON cannot be empty.");
116→
117→    JsonDocument doc;
118→    try
119→    {
120→        doc = JsonDocument.Parse(json);
121→    }
122→    catch (JsonException ex)
123→    {
124→        throw new ArgumentException($"Invalid JSON configuration: {ex.Message}", ex);
125→    }
126→
127→    var root = doc.RootElement;
128→
129→    if (!root.TryGetProperty("matrix", out var matrixElement))
130→        throw new ArgumentException("Configuration must contain a 'matrix' property.");
131→
132→    return new MatrixConfig
133→    {
134→        Matrix = ParseDimensions(matrixElement),
135→        Include = ParseRules(root, "include"),
136→        Exclude = ParseRules(root, "exclude"),
137→        FailFast = GetBool(root, "fail-fast", true),
138→        MaxParallel = GetNullableInt(root, "max-parallel"),
139→        MaxMatrixSize = GetInt(root, "max-matrix-size", 256)
140→    };
141→}
142→
143→static Dictionary<string, List<string>> ParseDimensions(JsonElement element)
144→{
145→    var dims = new Dictionary<string, List<string>>();
146→    foreach (var prop in element.EnumerateObject())
147→    {
148→        if (prop.Value.ValueKind != JsonValueKind.Array) continue;
149→        dims[prop.Name] = prop.Value.EnumerateArray().Select(ToStr).ToList();
150→    }
151→    return dims;
152→}
153→
154→static List<Dictionary<string, string>> ParseRules(JsonElement root, string name)
155→{
156→    if (!root.TryGetProperty(name, out var arr) || arr.ValueKind != JsonValueKind.Array)
157→        return new();
158→    return arr.EnumerateArray()
159→        .Select(item => item.EnumerateObject().ToDictionary(p => p.Name, p => ToStr(p.Value)))
160→        .ToList();
161→}
162→
163→static string ToStr(JsonElement e) => e.ValueKind switch
164→{
165→    JsonValueKind.String => e.GetString() ?? "",
166→    JsonValueKind.Number => e.GetRawText(),
167→    JsonValueKind.True => "true",
168→    JsonValueKind.False => "false",
169→    _ => e.GetRawText()
170→};
171→
172→static bool GetBool(JsonElement root, string name, bool def)
173→{
174→    if (root.TryGetProperty(name, out var p))
175→        return p.ValueKind == JsonValueKind.True;
176→    return def;
177→}
178→
179→static int? GetNullableInt(JsonElement root, string name)
180→{
181→    if (root.TryGetProperty(name, out var p) && p.ValueKind == JsonValueKind.Number)
182→        return p.GetInt32();
183→    return null;
184→}
185→
186→static int GetInt(JsonElement root, string name, int def)
187→{
188→    if (root.TryGetProperty(name, out var p) && p.ValueKind == JsonValueKind.Number)
189→        return p.GetInt32();
190→    return def;
191→}
