193→// --- Matrix Generation ---
194→
195→static MatrixResult GenerateMatrix(MatrixConfig config)
196→{
197→    var combos = CartesianProduct(config.Matrix);
198→    combos = ApplyExcludes(combos, config.Exclude);
199→    combos = ApplyIncludes(combos, config.Include);
200→    ValidateSize(combos.Count, config.MaxMatrixSize);
201→
202→    return new MatrixResult
203→    {
204→        Combinations = combos,
205→        MaxParallel = config.MaxParallel,
206→        FailFast = config.FailFast
207→    };
208→}
209→
210→static List<Dictionary<string, string>> CartesianProduct(Dictionary<string, List<string>> matrix)
211→{
212→    if (matrix.Count == 0) return new();
213→
214→    var result = new List<Dictionary<string, string>> { new() };
215→    foreach (var (key, values) in matrix)
216→    {
217→        if (values.Count == 0)
218→            throw new ArgumentException($"Matrix dimension '{key}' has no values.");
219→
220→        var expanded = new List<Dictionary<string, string>>();
221→        foreach (var combo in result)
222→            foreach (var val in values)
223→            {
224→                var newCombo = new Dictionary<string, string>(combo) { [key] = val };
225→                expanded.Add(newCombo);
226→            }
227→        result = expanded;
228→    }
229→    return result;
230→}
231→
232→static List<Dictionary<string, string>> ApplyExcludes(
233→    List<Dictionary<string, string>> combos, List<Dictionary<string, string>> rules)
234→{
235→    if (rules.Count == 0) return combos;
236→    return combos.Where(c => !rules.Any(r => Matches(c, r))).ToList();
237→}
238→
239→static List<Dictionary<string, string>> ApplyIncludes(
240→    List<Dictionary<string, string>> combos, List<Dictionary<string, string>> rules)
241→{
242→    if (rules.Count == 0) return combos;
243→
244→    var result = combos.Select(c => new Dictionary<string, string>(c)).ToList();
245→    foreach (var inc in rules)
246→    {
247→        bool merged = false;
248→        for (int i = 0; i < result.Count; i++)
249→        {
250→            if (IncludeMatches(result[i], inc))
251→            {
252→                foreach (var (k, v) in inc) result[i][k] = v;
253→                merged = true;
254→            }
255→        }
256→        if (!merged) result.Add(new Dictionary<string, string>(inc));
257→    }
258→    return result;
259→}
260→
261→// For exclude rules: ALL keys in the rule must be present in the combo with same values
262→static bool Matches(Dictionary<string, string> combo, Dictionary<string, string> rule) =>
263→    rule.All(kv => combo.TryGetValue(kv.Key, out var v) && v == kv.Value);
264→
265→// For include rules: all OVERLAPPING keys must match, and there must be at least one overlap
